#include<bits/stdc++.h>
using namespace std;

long long ans=0,n,num=0,num2;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        int x;
        cin>>x;
        if(x==1){
            if(num2!=0) num-=pow(2,num2-1);
            if(num<0) num=0;
            num2=0;
            if(num+1<=2){
                ans++;
                num++;
            }else if(num+1<=6){
                ans+=2;
                num++;
            }else if(num+1<=29){
                ans+=3;
                num++;
            }else if(num+1<=119){
                ans+=4;
                num++;
            }else if(num+1<=364){
                ans+=5;
                num++;
            }else{
                ans+=6;
                num++;
            }
        }else{
            num2++;
        }
    }
    cout<<ans;
    return 0;
}
